sql:
SELECT customer_id
FROM customers
WHERE customer_id NOT IN (
  SELECT customer_id 
  FROM customer_segment_assignments
);

SELECT product_id, COUNT(DISTINCT customer_id) AS number_of_customers
FROM sales
GROUP BY product_id;

external_knowledge:
married = 1 refers to customers who are married;
dependents > 0 means customers who have dependents;
product_id = 0 is a specific product identifier;
"little ones" refers to dependents;
"earn more on average" refers to average annual income.

sql:
SELECT SUM(c.annual_income)
FROM customers c
JOIN sales s ON c.customer_id = s.customer_id;

SELECT COUNT(DISTINCT customer_id) AS num_customers
FROM sales
WHERE sale_channel = 'online';
